  "example_4_alter_add_column": {
    "description": "Adding a new column to an existing entity using SchemaDesign.Tables[] format. taskComplete: true returns to parent. Never include a message or responseForm — the parent presents the prototype.",
    "taskComplete": true,
    "payloadChangeRequest": {
      "newElements": {
        "SchemaDesign": {
          "Tables": [
            {
              "ModificationType": "alter",
              "Description": "Key checkpoints and milestones for projects.",
              "Prototype": "| Column | SQL Type | Required | Default | Description |\n|--------|----------|----------|---------|-------------|\n| Title | NVARCHAR(200) | \u2705 Yes | \u2014 | Milestone label |\n| Status | NVARCHAR(50) | \u2705 Yes | ''Active'' | Active, Completed, Cancelled |\n| Priority | INT | No | \u2014 | 1 (high) to 5 (low) |",
              "TableDefinition": {
                "SchemaName": "__mj_UDT",
                "TableName": "ProjectMilestones",
