                "Description": "Key checkpoints and milestones for projects.",
                "Columns": [
                  { "Name": "Title", "RawSqlType": "NVARCHAR(200)", "IsNullable": false, "Description": "Short label for the milestone." },
                  { "Name": "Status", "RawSqlType": "NVARCHAR(50)", "IsNullable": false, "DefaultValue": "''Active''", "Description": "Active, Completed, Cancelled." },
                  { "Name": "Priority", "Type": "integer", "IsNullable": true, "Description": "Priority ranking: 1=highest, 5=lowest." }
                ]
              }
            }
          ]
        }
      }
    },
    "nextStep": {
      "type": "Success"
    }
