DECLARE @ID_46cdf6a7 UNIQUEIDENTIFIER,
@Namespace_46cdf6a7 NVARCHAR(MAX),
@Name_46cdf6a7 NVARCHAR(500),
@Version_46cdf6a7 NVARCHAR(50),
@VersionSequence_46cdf6a7 INT,
@Title_46cdf6a7 NVARCHAR(1000),
@Description_46cdf6a7 NVARCHAR(MAX),
@Type_46cdf6a7 NVARCHAR(255),
@Status_46cdf6a7 NVARCHAR(50),
@DeveloperName_46cdf6a7 NVARCHAR(255),
@DeveloperEmail_46cdf6a7 NVARCHAR(255),
@DeveloperOrganization_46cdf6a7 NVARCHAR(255),
@SourceRegistryID_46cdf6a7 UNIQUEIDENTIFIER,
@ReplicatedAt_46cdf6a7 DATETIMEOFFSET,
@LastSyncedAt_46cdf6a7 DATETIMEOFFSET,
@Specification_46cdf6a7 NVARCHAR(MAX),
@FunctionalRequirements_46cdf6a7 NVARCHAR(MAX),
@TechnicalDesign_46cdf6a7 NVARCHAR(MAX),
@FunctionalRequirementsVector_46cdf6a7 NVARCHAR(MAX),
@TechnicalDesignVector_46cdf6a7 NVARCHAR(MAX),
@HasCustomProps_46cdf6a7 BIT,
@HasCustomEvents_46cdf6a7 BIT,
@RequiresData_46cdf6a7 BIT,
@DependencyCount_46cdf6a7 INT,
@TechnicalDesignVectorEmbeddingModelID_46cdf6a7 NVARCHAR(MAX),
@FunctionalRequirementsVectorEmbeddingModelID_46cdf6a7 NVARCHAR(MAX),
@HasRequiredCustomProps_46cdf6a7 BIT
SET
  @ID_46cdf6a7 = 'A0D8DC78-9E2D-4866-91F4-7B474B2E7A9F'
SET
  @Namespace_46cdf6a7 = N'Admin/Applications'
SET
  @Name_46cdf6a7 = N'InteractiveApplicationForm'
SET
  @Version_46cdf6a7 = N'1.0.0'
SET
  @VersionSequence_46cdf6a7 = 1
SET
  @Title_46cdf6a7 = N'Interactive Application Form'
SET
  @Description_46cdf6a7 = N'Worked example for the Interactive Forms substrate (PR #2609). Renders MJ Application records via a React component, mounted by the Angular InteractiveFormComponent wrapper. Demonstrates the FormHostProps contract end-to-end: view/edit modes driven by host, dirty-field diff emitted via BeforeSave, mode toggles via EditModeChangeRequested.'
SET
  @Type_46cdf6a7 = N'Other'
SET
  @Status_46cdf6a7 = N'Published'
SET
  @Specification_46cdf6a7 = N'{"name":"InteractiveApplicationForm","location":"embedded","code":"// Worked example for the Interactive Forms substrate (PR #2609).\n// Renders MJ Application records via a React component, mounted by the\n// Angular InteractiveFormComponent wrapper.\n//\n// Modes (driven by FormHostProps.mode from the wrapper):\n//   - view   : read-only card — no buttons (toolbar above handles Edit/Delete)\n//   - edit   : inputs editable — no buttons (toolbar above handles Save/Cancel)\n//   - create : header swaps to \"New Application\" — no buttons (toolbar handles)\n//\n// Toolbar wiring (Save / Cancel come from <mj-record-form-container>, not here):\n//   1. Component registers `RequestSave` + `RequestCancel` methods via\n//      `callbacks.RegisterMethod` in a useEffect.\n//   2. Host toolbar Save -> wrapper invokes `RequestSave` on this component.\n//   3. `RequestSave` handler emits `BeforeSave({ dirtyFields })` -> wrapper\n//      applies diff to BaseEntity -> record.Save() -> re-flows new record.\n//   4. Host toolbar Cancel -> wrapper invokes `RequestCancel` -> handler\n//      clears local draft -> wrapper calls EndEditMode -> re-flows mode=''view''.\n//\n// We use a draftRef so the registered method always reads the latest draft\n// (registering inside a useEffect with `[draft]` would re-register on every\n// keystroke, which is wasteful; useRef tracks the current value without\n// breaking the closure).\n//\n// Mode handling rule of thumb: never setState({ mode }) locally. The wrapper\n// owns mode; this component only reads it from FormHostProps.\n\nfunction InteractiveApplicationForm({\n  // FormHostProps (from the Angular wrapper)\n  entityName,\n  primaryKey,\n  record,\n  entityMetadata,\n  mode,\n  canEdit,\n  canDelete,\n  canCreate,\n  // Standard component props\n  utilities,\n  styles,\n  components,\n  callbacks,\n  savedUserSettings,\n  onSaveUserSettings,\n}) {\n  const [draft, setDraft] = React.useState({});\n\n  // Track latest draft in a ref so the methods we register below always see\n  // the current value without us having to re-register on every keystroke.\n  const draftRef = React.useRef({});\n  React.useEffect(() => {\n    draftRef.current = draft;\n  }, [draft]);\n\n  const isCreate = mode === \"create\";\n  const isEdit = mode === \"edit\";\n  const isView = mode === \"view\";\n  const editing = isEdit || isCreate;\n\n  // Reset draft when a new record loads, or when we return to view mode.\n  React.useEffect(() => {\n    setDraft({});\n  }, [primaryKey && JSON.stringify(primaryKey), isView]);\n\n  // Register the host-callable methods exactly once. The wrapper invokes\n  // these when the toolbar fires Save / Cancel — that''s how the toolbar\n  // above this component gets the React draft state flushed.\n  React.useEffect(() => {\n    callbacks?.RegisterMethod?.(\"RequestSave\", () => {\n      callbacks?.NotifyEvent?.(\"BeforeSave\", {\n        dirtyFields: { ...draftRef.current },\n        cancel: false,\n        timestamp: new Date(),\n      });\n      // Don''t clear draft here — wait for the wrapper to confirm save\n      // succeeded and re-flow the record. If save fails, the draft is\n      // still around for the user to retry.\n    });\n    callbacks?.RegisterMethod?.(\"RequestCancel\", () => {\n      setDraft({});\n      // Wrapper will EndEditMode itself after this method returns.\n    });\n  }, []);\n\n  const value = (field) => (field in draft ? draft[field] : record?.[field]);\n\n  const setField = (field, v) => {\n    setDraft((d) => ({ ...d, [field]: v }));\n    callbacks?.NotifyEvent?.(\"FieldChanged\", {\n      fieldName: field,\n      oldValue: record?.[field],\n      newValue: v,\n      timestamp: new Date(),\n    });\n  };\n\n  // ── styles ─────────────────────────────────────────────────────────────\n  const colors = {\n    panel: \"var(--mj-bg-surface, #fff)\",\n    border: \"var(--mj-border-default, #e0e0e0)\",\n    text: \"var(--mj-text-primary, #1f2937)\",\n    muted: \"var(--mj-text-muted, #64748b)\",\n    primary: \"var(--mj-brand-primary, #5B4FE9)\",\n    primaryHover: \"var(--mj-brand-primary-hover, #4538d6)\",\n    success: \"var(--mj-status-success, #16a34a)\",\n    successBg: \"var(--mj-status-success-bg, #dcfce7)\",\n    danger: \"var(--mj-status-error, #dc2626)\",\n    dangerBg: \"var(--mj-status-error-bg, #fee2e2)\",\n    badge: \"var(--mj-bg-surface-sunken, #f1f5f9)\",\n    createBg: \"var(--mj-status-info-bg, #dbeafe)\",\n    createText: \"var(--mj-status-info-text, #1e40af)\",\n  };\n\n  const wrap = {\n    padding: 24,\n    background: colors.panel,\n    color: colors.text,\n    fontFamily: ''-apple-system, \"Inter\", \"Segoe UI\", Roboto, sans-serif'',\n    borderRadius: 8,\n    border: `1px solid $' + CAST(N'' AS NVARCHAR(MAX)) + N'{colors.border}`,\n  };\n\n  const header = {\n    display: \"flex\",\n    alignItems: \"center\",\n    gap: 16,\n    paddingBottom: 16,\n    borderBottom: `1px solid $' + CAST(N'' AS NVARCHAR(MAX)) + N'{colors.border}`,\n    marginBottom: 20,\n  };\n\n  const createHeader = {\n    paddingBottom: 16,\n    borderBottom: `1px solid $' + CAST(N'' AS NVARCHAR(MAX)) + N'{colors.border}`,\n    marginBottom: 20,\n  };\n\n  const iconBox = {\n    width: 56,\n    height: 56,\n    borderRadius: 12,\n    background: colors.badge,\n    display: \"flex\",\n    alignItems: \"center\",\n    justifyContent: \"center\",\n    fontSize: 28,\n    color: colors.primary,\n    flexShrink: 0,\n  };\n\n  const titleBlock = { flex: 1, minWidth: 0 };\n\n  const title = {\n    margin: 0,\n    fontSize: 22,\n    fontWeight: 600,\n    lineHeight: 1.2,\n    color: colors.text,\n  };\n\n  const subtitle = {\n    margin: \"4px 0 0\",\n    fontSize: 13,\n    color: colors.muted,\n    display: \"flex\",\n    gap: 8,\n    flexWrap: \"wrap\",\n  };\n\n  const badge = {\n    display: \"inline-flex\",\n    alignItems: \"center\",\n    gap: 4,\n    padding: \"2px 8px\",\n    background: colors.badge,\n    borderRadius: 999,\n    fontSize: 12,\n    color: colors.text,\n  };\n\n  const successBadge = {\n    ...badge,\n    background: colors.successBg,\n    color: colors.success,\n  };\n\n  const createBadge = {\n    ...badge,\n    background: colors.createBg,\n    color: colors.createText,\n  };\n\n  const fieldRow = { display: \"grid\", gridTemplateColumns: \"160px 1fr\", gap: 12, padding: \"10px 0\", alignItems: \"start\" };\n  const label = { color: colors.muted, fontSize: 13, paddingTop: 6 };\n  const textInput = {\n    width: \"100%\",\n    padding: \"8px 12px\",\n    border: `1px solid $' + CAST(N'' AS NVARCHAR(MAX)) + N'{colors.border}`,\n    borderRadius: 6,\n    fontSize: 14,\n    color: colors.text,\n    background: colors.panel,\n    boxSizing: \"border-box\",\n  };\n  const textArea = { ...textInput, minHeight: 80, fontFamily: \"inherit\", resize: \"vertical\" };\n  const readOnlyValue = { padding: \"6px 0\", fontSize: 14, color: colors.text, whiteSpace: \"pre-wrap\" };\n\n  // No button/footer styles — Edit / Save / Cancel / Delete all come from\n  // the host''s <mj-record-form-container> toolbar above this component.\n\n  // ── render ─────────────────────────────────────────────────────────────\n  if (!record) {\n    return <div style={{ ...wrap, color: colors.muted }}>No application record loaded.</div>;\n  }\n\n  const name = value(\"Name\") ?? \"\";\n  const description = value(\"Description\") ?? \"\";\n  const icon = value(\"Icon\") ?? \"fa-cube\";\n  const defaultForNewUser = !!value(\"DefaultForNewUser\");\n  const status = value(\"Status\") ?? \"\";\n\n  // Header: distinct treatment in create mode so the user knows they''re\n  // making a fresh record (no name yet, no status badge, no icon to render).\n  const renderHeader = () => {\n    if (isCreate) {\n      return (\n        <div style={createHeader}>\n          <div style={{ display: \"flex\", alignItems: \"center\", gap: 12 }}>\n            <span style={createBadge}>＋ New Application</span>\n            <span style={badge}>🧪 PR #2609 example (create mode)</span>\n          </div>\n          <h2 style={{ ...title, marginTop: 12 }}>{name || \"Untitled application\"}</h2>\n          <p style={{ ...subtitle, marginTop: 4 }}>Fill in the fields below, then Save to create.</p>\n        </div>\n      );\n    }\n    return (\n      <div style={header}>\n        <div style={iconBox}>\n          <i className={`fa-solid $' + CAST(N'' AS NVARCHAR(MAX)) + N'{icon}`} />\n        </div>\n        <div style={titleBlock}>\n          <h2 style={title}>{name || \"(unnamed application)\"}</h2>\n          <div style={subtitle}>\n            <span style={badge}>🧪 Interactive Form (PR #2609 example)</span>\n            {status && <span style={status === \"Active\" ? successBadge : badge}>{status}</span>}\n            {defaultForNewUser && <span style={successBadge}>Default for new users</span>}\n          </div>\n        </div>\n      </div>\n    );\n  };\n\n  // No in-form footer. Edit / Save / Cancel / Delete are all owned by the\n  // host''s <mj-record-form-container> toolbar above this component. When\n  // the toolbar fires Save, the wrapper invokes `RequestSave` (registered\n  // in the useEffect above) which emits BeforeSave with the current draft;\n  // same for Cancel via `RequestCancel`.\n\n  return (\n    <div style={wrap}>\n      {renderHeader()}\n\n      {/* fields — always render, but use input vs read-only display based on `editing` */}\n      <div>\n        <div style={fieldRow}>\n          <div style={label}>Name</div>\n          {editing ? (\n            <input\n              type=\"text\"\n              style={textInput}\n              value={name}\n              onChange={(e) => setField(\"Name\", e.target.value)}\n              disabled={!canEdit && !canCreate}\n              placeholder={isCreate ? \"My Application\" : \"\"}\n            />\n          ) : (\n            <div style={readOnlyValue}>{name || \"—\"}</div>\n          )}\n        </div>\n        <div style={fieldRow}>\n          <div style={label}>Description</div>\n          {editing ? (\n            <textarea\n              style={textArea}\n              value={description}\n              onChange={(e) => setField(\"Description\", e.target.value)}\n              disabled={!canEdit && !canCreate}\n              placeholder={isCreate ? \"What does this application do?\" : \"\"}\n            />\n          ) : (\n            <div style={readOnlyValue}>{description || \"—\"}</div>\n          )}\n        </div>\n        <div style={fieldRow}>\n          <div style={label}>Icon</div>\n          {editing ? (\n            <input\n              type=\"text\"\n              style={textInput}\n              value={icon}\n              placeholder=\"fa-* class name (e.g. fa-cube)\"\n              onChange={(e) => setField(\"Icon\", e.target.value)}\n              disabled={!canEdit && !canCreate}\n            />\n          ) : (\n            <div style={readOnlyValue}>{icon || \"—\"}</div>\n          )}\n        </div>\n        <div style={fieldRow}>\n          <div style={label}>Default for new users</div>\n          {editing ? (\n            <input\n              type=\"checkbox\"\n              checked={defaultForNewUser}\n              onChange={(e) => setField(\"DefaultForNewUser\", e.target.checked)}\n              disabled={!canEdit && !canCreate}\n            />\n          ) : (\n            <div style={readOnlyValue}>{defaultForNewUser ? \"Yes\" : \"No\"}</div>\n          )}\n        </div>\n      </div>\n\n      {/* No footer — toolbar handles Save / Cancel / Edit / Delete. */}\n    </div>\n  );\n}\n","title":"Interactive Application Form","description":"Worked example for the Interactive Forms substrate (PR #2609). Renders MJ Application records via a React component, mounted by the Angular InteractiveFormComponent wrapper. Demonstrates the FormHostProps contract end-to-end: view/edit modes driven by host, dirty-field diff emitted via BeforeSave, mode toggles via EditModeChangeRequested.","type":"form","componentRole":"form","category":"Admin/Applications","properties":[{"name":"record","type":"object","required":true,"description":"Plain snapshot of the BaseEntity (BaseEntity.GetAll() result). Read-only — mutations go through the host via BeforeSave."},{"name":"mode","type":"string","required":true,"description":"view | edit | create. Source of truth is the host; component requests changes via EditModeChangeRequested."},{"name":"canEdit","type":"boolean","required":true,"description":"Whether the current user has edit permission on this entity."},{"name":"canDelete","type":"boolean","required":true,"description":"Whether the current user has delete permission."},{"name":"canCreate","type":"boolean","required":true,"description":"Whether the current user has create permission."}],"events":[{"name":"BeforeSave","description":"Component requests the host commit the dirty-field diff. Host applies to BaseEntity and calls Save().","cancelable":true,"pairedEvent":"AfterSave","parameters":[{"name":"dirtyFields","type":"object","description":"Map of field name -> new value for only fields that changed."}]},{"name":"EditModeChangeRequested","description":"Component asks the host to enter/leave edit mode. Host flips state; new mode flows back via FormHostProps.mode.","cancelable":true,"parameters":[{"name":"requestedMode","type":"string","description":"''view'' or ''edit''."}]},{"name":"FieldChanged","description":"Component reports a single-field edit. Non-cancelable. Drives dirty-state tracking and downstream observers.","parameters":[{"name":"fieldName","type":"string","description":"Name of the field that changed."},{"name":"oldValue","type":"any","description":"Prior value."},{"name":"newValue","type":"any","description":"New value."}]}],"exampleUsage":"Mounted automatically by InteractiveFormComponent when an EntityFormOverride row resolves to this component for an Applications record. Not consumed by other components directly.","functionalRequirements":"Render a single MJ Application record with Name, Description, Icon, DefaultForNewUser, and Status. View mode is read-only with an Edit button. Edit mode shows inputs + Save/Cancel; Save is disabled until at least one field is dirty. Header shows the application''s icon, name, status badge, and ''Default for new users'' badge when applicable. Always identify itself visibly as the PR #2609 example so a reviewer can tell it from the generated Angular form.","technicalDesign":"Function component. Receives FormHostProps (record, mode, canEdit/Delete/Create, entityMetadata) spread alongside the standard utilities/callbacks/styles/components props. Maintains a local `draft` object keyed by field name; `value(field)` reads from draft, falling back to record. Save emits NotifyEvent(''BeforeSave'', { dirtyFields, cancel: false }) and clears the local draft; the Angular wrapper handles the actual record.Save(). Mode is treated as host-owned — local UI never directly toggles it; instead EditModeChangeRequested asks the host to switch. Cancel clears the draft AND requests view mode. Styles use --mj-* design tokens with hardcoded fallbacks so the component still renders if loaded outside MJExplorer."}'
SET
  @FunctionalRequirements_46cdf6a7 = N'Render a single MJ Application record with Name, Description, Icon, DefaultForNewUser, and Status. View mode is read-only with an Edit button. Edit mode shows inputs + Save/Cancel; Save is disabled until at least one field is dirty. Header shows the application''s icon, name, status badge, and ''Default for new users'' badge when applicable. Always identify itself visibly as the PR #2609 example so a reviewer can tell it from the generated Angular form.'
SET
  @TechnicalDesign_46cdf6a7 = N'Function component. Receives FormHostProps (record, mode, canEdit/Delete/Create, entityMetadata) spread alongside the standard utilities/callbacks/styles/components props. Maintains a local `draft` object keyed by field name; `value(field)` reads from draft, falling back to record. Save emits NotifyEvent(''BeforeSave'', { dirtyFields, cancel: false }) and clears the local draft; the Angular wrapper handles the actual record.Save(). Mode is treated as host-owned — local UI never directly toggles it; instead EditModeChangeRequested asks the host to switch. Cancel clears the draft AND requests view mode. Styles use --mj-* design tokens with hardcoded fallbacks so the component still renders if loaded outside MJExplorer.'
