  @Name_1dee1690 = N'T25 - Multiple Tab Workflow'
SET
  @Description_1dee1690 = N'Opens three different entity types in separate tabs, verifies each tab has correct content, closes the middle tab, and verifies remaining tabs work.'
SET
  @Status_1dee1690 = N'Active'
SET
  @InputDefinition_1dee1690 = N'{
  "goal": "Navigate to Data Explorer. Open three different records, each in its own tab, by following these steps for each one: (1) select an entity type (try Members first, then Events, then a third entity such as Board Members), (2) click any row in the records grid so the detail panel slides out on the right, (3) Shift+Click the ''Open Full Record'' button at the bottom of that detail panel — Shift+Click opens the record in a new tab instead of replacing the current one. After opening all three records this way, three tabs will appear underneath the top navigation. Switch between the tabs to confirm each shows its own record. Then close the middle tab (click the small × on it) and confirm the remaining two tabs are still functional with their original record content. Note: clicking entity cards in the entity list does NOT open new tabs — only Shift+Click on the ''Open Full Record'' button does.",
  "startUrl": "http://localhost:4200",
  "allowedDomains": [
    "localhost",
    "*.auth0.com"
  ],
  "auth": {
    "bindings": [
      {
        "domains": [
